import { z } from 'zod';
import {
  trimAndRequire,
  phoneNumberSchema,
  mapFieldErrors,
} from './helpers';

export const createWalletTopUpSchema = (t) =>
  z
    .object({
      paymentMethod: z.enum(['mobileMoney', 'card', 'bank'], {
        errorMap: () => ({
          message: 'Select a payment method',
        }),
      }),
      phoneCountryCode: z.string().optional(),
      firstName: trimAndRequire(
        t('firstNameRequired', {
          ns: 'common',
          defaultValue: 'First name is required',
        })
      ),
      lastName: trimAndRequire(
        t('lastNameRequired', {
          ns: 'common',
          defaultValue: 'Last name is required',
        })
      ),
      email: z.string().optional(),
      phone: z.string().optional(),
      provider: z.enum(['mtn', 'telecel', 'airtel-tigo']).optional(),
      accountNumber: z.string().optional(),
      // Card payment fields
      cardNumber: z.string().optional(),
      cardExpiry: z.string().optional(),
      cardCvv: z.string().optional(),
      cardholderName: z.string().optional(),
      amount: z
        .string()
        .trim()
        .transform((val) => {
          const cleaned = val.replace(/,/g, '');
          return cleaned === '' ? NaN : Number(cleaned);
        })
        .refine((val) => !Number.isNaN(val), {
          message: t('invalidAmount', {
            ns: 'wallet',
            defaultValue: 'Please enter a valid amount greater than 0',
          }),
        })
        .refine((val) => val > 0, {
          message: t('amountPositive', {
            ns: 'wallet',
            defaultValue: 'Amount must be greater than zero',
          }),
        })
        .refine((val) => val <= 1_000_000, {
          message: t('amountTooLarge', {
            ns: 'wallet',
            defaultValue: 'Amount cannot exceed 1,000,000',
          }),
        }),
    })
    .refine(
      (data) => {
        if (data.paymentMethod === 'mobileMoney' || data.paymentMethod === 'bank') {
          return (
            data.phoneCountryCode &&
            data.phone &&
            phoneNumberSchema(
              t('invalidPhoneNumber', {
                ns: 'wallet',
                defaultValue: 'Enter a valid phone number',
              }),
              t('phoneNumberLength', {
                ns: 'wallet',
                defaultValue: 'Phone number must be between 7 and 15 digits',
              })
            ).safeParse(data.phone).success &&
            data.provider
          );
        }
        return true;
      },
      {
        message: t('invalidPhoneNumber', {
          ns: 'wallet',
          defaultValue: 'Enter a valid phone number',
        }),
        path: ['phone'],
      }
    )
    .refine(
      (data) => {
        if (data.paymentMethod === 'mobileMoney' || data.paymentMethod === 'bank') {
          return data.provider;
        }
        return true;
      },
      {
        message: t('providerRequired', {
          ns: 'wallet',
          defaultValue: 'Select a provider',
        }),
        path: ['provider'],
      }
    )
    // Bank account number is no longer required; keep optional with empty string allowed
    .refine(
      (data) => {
        if (data.paymentMethod === 'bank') {
          return !!data.email && z.string().email().safeParse(data.email).success;
        }
        return true;
      },
      {
        message: t('emailRequired', {
          ns: 'common',
          defaultValue: 'Email is required',
        }),
        path: ['email'],
      }
    )
    .refine(
      (data) => {
        if (data.paymentMethod === 'card') {
          const cardNumber = data.cardNumber?.replace(/\s/g, '') || '';
          return cardNumber.length >= 13 && cardNumber.length <= 19;
        }
        return true;
      },
      {
        message: 'Card number must be between 13 and 19 digits',
        path: ['cardNumber'],
      }
    )
    .refine(
      (data) => {
        if (data.paymentMethod === 'card') {
          const expiry = data.cardExpiry || '';
          const expiryRegex = /^(0[1-9]|1[0-2])\/\d{2}$/;
          return expiryRegex.test(expiry);
        }
        return true;
      },
      {
        message: 'Enter a valid expiry date (MM/YY)',
        path: ['cardExpiry'],
      }
    )
    .refine(
      (data) => {
        if (data.paymentMethod === 'card') {
          const cvv = data.cardCvv || '';
          return cvv.length >= 3 && cvv.length <= 4;
        }
        return true;
      },
      {
        message: 'CVV must be 3 or 4 digits',
        path: ['cardCvv'],
      }
    )
    .refine(
      (data) => {
        if (data.paymentMethod === 'card') {
          return data.cardholderName && data.cardholderName.trim().length > 0;
        }
        return true;
      },
      {
        message: 'Cardholder name is required',
        path: ['cardholderName'],
      }
    )
    .transform((data) => ({
      ...data,
      firstName: data.firstName.trim(),
      lastName: data.lastName.trim(),
      email: data.email?.trim() || '',
      phone: data.phone?.trim() || '',
      phoneCountryCode: data.phoneCountryCode?.trim() || '',
      amount: data.amount,
      provider: data.provider || '',
      accountNumber: data.accountNumber?.trim() || '',
      cardNumber: data.cardNumber?.replace(/\s/g, '') || '',
      cardExpiry: data.cardExpiry || '',
      cardCvv: data.cardCvv || '',
      cardholderName: data.cardholderName?.trim() || '',
    }));

export const createCheckoutLinkSchema = (t) =>
  z
    .object({
      paymentMethod: z.enum(['mobileMoney', 'card', 'bank'], {
        errorMap: () => ({
          message: 'Select a payment method',
        }),
      }),
      phoneCountryCode: z.string().optional(),
      firstName: trimAndRequire(
        t('firstNameRequired', {
          ns: 'common',
          defaultValue: 'First name is required',
        })
      ),
      lastName: trimAndRequire(
        t('lastNameRequired', {
          ns: 'common',
          defaultValue: 'Last name is required',
        })
      ),
      email: z.string().optional(),
      phone: z.string().optional(),
      provider: z.enum(['mtn', 'telecel', 'airtel-tigo']).optional(),
      accountNumber: z.string().optional(),
      // Card payment fields
      cardNumber: z.string().optional(),
      cardExpiry: z.string().optional(),
      cardCvv: z.string().optional(),
      cardholderName: z.string().optional(),
      amount: z
        .string()
        .trim()
        .transform((val) => {
          const cleaned = val.replace(/,/g, '');
          return cleaned === '' ? NaN : Number(cleaned);
        })
        .refine((val) => !Number.isNaN(val), {
          message: t('invalidAmount', {
            ns: 'wallet',
            defaultValue: 'Please enter a valid amount greater than 0',
          }),
        })
        .refine((val) => val > 0, {
          message: t('amountPositive', {
            ns: 'wallet',
            defaultValue: 'Amount must be greater than zero',
          }),
        })
        .refine((val) => val <= 1_000_000, {
          message: t('amountTooLarge', {
            ns: 'wallet',
            defaultValue: 'Amount cannot exceed 1,000,000',
          }),
        }),
      items: z
        .array(
          z.object({
            description: trimAndRequire(
              t('itemDescriptionRequired', { ns: 'invoicing', defaultValue: 'Item description is required' })
            ).max(200, t('itemDescriptionTooLong', { ns: 'invoicing', defaultValue: 'Description too long' })),
            quantity: z
              .union([z.number(), z.string()])
              .transform((val) => {
                const num = typeof val === 'string' ? parseFloat(val) : val;
                return isNaN(num) ? 0 : num;
              })
              .refine((val) => val > 0, {
                message: t('quantityMustBePositive', { ns: 'invoicing', defaultValue: 'Quantity must be positive' }),
              })
              .refine((val) => val <= 1000000, {
                message: t('quantityTooLarge', { ns: 'invoicing', defaultValue: 'Quantity too large' }),
              }),
            unitPrice: z
              .union([z.number(), z.string()])
              .transform((val) => {
                const num = typeof val === 'string' ? parseFloat(val) : val;
                return isNaN(num) ? 0 : num;
              })
              .refine((val) => val > 0, {
                message: t('unitPriceMustBePositive', { ns: 'invoicing', defaultValue: 'Unit price must be greater than 0' }),
              })
              .refine((val) => val <= 1000000000, {
                message: t('unitPriceTooLarge', { ns: 'invoicing', defaultValue: 'Unit price too large' }),
              }),
            total: z.number().optional(),
          })
        )
        .min(1, t('atLeastOneItemRequired', { ns: 'invoicing', defaultValue: 'At least one item is required' })),
    })
    .refine(
      (data) => {
        if (data.paymentMethod === 'mobileMoney' || data.paymentMethod === 'bank') {
          return (
            data.phoneCountryCode &&
            data.phone &&
            phoneNumberSchema(
              t('invalidPhoneNumber', {
                ns: 'wallet',
                defaultValue: 'Enter a valid phone number',
              }),
              t('phoneNumberLength', {
                ns: 'wallet',
                defaultValue: 'Phone number must be between 7 and 15 digits',
              })
            ).safeParse(data.phone).success &&
            data.provider
          );
        }
        return true;
      },
      {
        message: t('invalidPhoneNumber', {
          ns: 'wallet',
          defaultValue: 'Enter a valid phone number',
        }),
        path: ['phone'],
      }
    )
    .refine(
      (data) => {
        if (data.paymentMethod === 'mobileMoney' || data.paymentMethod === 'bank') {
          return data.provider;
        }
        return true;
      },
      {
        message: t('providerRequired', {
          ns: 'wallet',
          defaultValue: 'Select a provider',
        }),
        path: ['provider'],
      }
    )
    .refine(
      (data) => {
        if (data.paymentMethod === 'bank') {
          return !!data.email && z.string().email().safeParse(data.email).success;
        }
        return true;
      },
      {
        message: t('emailRequired', {
          ns: 'common',
          defaultValue: 'Email is required',
        }),
        path: ['email'],
      }
    )
    .refine(
      (data) => {
        if (data.paymentMethod === 'card') {
          const cardNumber = data.cardNumber?.replace(/\s/g, '') || '';
          return cardNumber.length >= 13 && cardNumber.length <= 19;
        }
        return true;
      },
      {
        message: 'Card number must be between 13 and 19 digits',
        path: ['cardNumber'],
      }
    )
    .refine(
      (data) => {
        if (data.paymentMethod === 'card') {
          const expiry = data.cardExpiry || '';
          const expiryRegex = /^(0[1-9]|1[0-2])\/\d{2}$/;
          return expiryRegex.test(expiry);
        }
        return true;
      },
      {
        message: 'Enter a valid expiry date (MM/YY)',
        path: ['cardExpiry'],
      }
    )
    .refine(
      (data) => {
        if (data.paymentMethod === 'card') {
          const cvv = data.cardCvv || '';
          return cvv.length >= 3 && cvv.length <= 4;
        }
        return true;
      },
      {
        message: 'CVV must be 3 or 4 digits',
        path: ['cardCvv'],
      }
    )
    .refine(
      (data) => {
        if (data.paymentMethod === 'card') {
          return data.cardholderName && data.cardholderName.trim().length > 0;
        }
        return true;
      },
      {
        message: 'Cardholder name is required',
        path: ['cardholderName'],
      }
    )
    .transform((data) => ({
      ...data,
      firstName: data.firstName.trim(),
      lastName: data.lastName.trim(),
      email: data.email?.trim() || '',
      phone: data.phone?.trim() || '',
      phoneCountryCode: data.phoneCountryCode?.trim() || '',
      amount: data.amount,
      provider: data.provider || '',
      accountNumber: data.accountNumber?.trim() || '',
      cardNumber: data.cardNumber?.replace(/\s/g, '') || '',
      cardExpiry: data.cardExpiry || '',
      cardCvv: data.cardCvv || '',
      cardholderName: data.cardholderName?.trim() || '',
      items: data.items,
    }));

export const createWalletTransferSchema = (t) =>
  z
    .object({
      phoneCountryCode: trimAndRequire(
        t('phoneCountryCodeRequired', {
          ns: 'wallet',
          defaultValue: 'Select a country code',
        })
      ),
      recipientQuery: trimAndRequire(
        t('recipientQueryRequired', {
          ns: 'wallet',
          defaultValue: 'Enter recipient details',
        })
      ).min(
        3,
        t('recipientQueryTooShort', {
          ns: 'wallet',
          defaultValue: 'Enter at least 3 characters',
        })
      ),
      amount: z
        .string()
        .trim()
        .transform((val) => (val === '' ? NaN : Number(val)))
        .refine((val) => !Number.isNaN(val), {
          message: t('invalidAmount', {
            ns: 'wallet',
            defaultValue: 'Please enter a valid amount greater than 0',
          }),
        })
        .refine((val) => val > 0, {
          message: t('amountPositive', {
            ns: 'wallet',
            defaultValue: 'Amount must be greater than zero',
          }),
        })
        .refine((val) => val <= 1_000_000, {
          message: t('amountTooLarge', {
            ns: 'wallet',
            defaultValue: 'Amount cannot exceed 1,000,000',
          }),
        }),
    })
    .transform((data) => ({
      phoneCountryCode: data.phoneCountryCode.trim(),
      recipientQuery: data.recipientQuery.trim(),
      amount: data.amount,
    }));

export { mapFieldErrors };


